var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CHOIENA_HB_NULL_NULL","text":{"KOREA":"휴우...... 인터뷰 중에 방송사고라니......","JPN":"ふぅ……インタビュー中に放送事故を起こすなんてね……","ENG":"*Sigh* An accident during the interview?","TWN":"呼……採訪中竟然發生放送事故……"},"stage":{"bg":"DORMITORY_2","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CHOIENA_HB_NULL_NULL","text":{"KOREA":"개인방송의 자유로운 진행방식을 무시하는 건 아니지만......","JPN":"個人配信ならではのフリーダムさは必要だと思うけど……","ENG":"I don't mean to meddle with the way you do your personal livestreams...","TWN":"雖然也不是要剝奪妳個人直播的自由……"},"stage":{"bg":"DORMITORY_2","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CHOIENA_HB_NULL_NULL","text":{"KOREA":"다음부턴 리허설 정도는 해봤으면 좋겠어.","JPN":"次からはリハーサルくらいはやっておいてほしいわ。","ENG":"But I hope you'd run a dry rehearsal next time.","TWN":"但希望下次妳能做個彩排。"},"stage":{"bg":"DORMITORY_2","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CHOIENA_HB_NULL_NULL","text":{"KOREA":"예기치 못한 대형폭발 때문에 방송이 꺼져버려서야 보시던 분들이 곤란하잖니?","JPN":"予期せぬ大爆発で配信が止まってしまったら、視聴者の方々に迷惑でしょう？","ENG":"We wouldn't want our viewers to see the screen go blank because of an unforeseen explosion, do we?","TWN":"因為意料之外的大爆炸導致中斷直播，妳這樣讓觀眾多為難啊。"},"stage":{"bg":"DORMITORY_2","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"으으...... 죄송해요, 이나 언니.","JPN":"うぅ……申し訳ないです、メグミさん。","ENG":"Aw... I'm so sorry, Ina.","TWN":"嗚嗚……對不起，理娜姐。"},"stage":{"bg":"DORMITORY_2","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L9_1","type":"dialog","speaker":"CHOIENA_HB_NULL_NULL","text":{"KOREA":"어허~ 내가 아니라 시청자 분들한테 사과해야지.","JPN":"こらこら、私じゃなくて、視聴者の皆様にきちんと謝らないと。","ENG":"It's the viewers you should be apologizing to.","TWN":"嗯哼～妳該道歉的不是我，而是向各位觀眾。"},"stage":{"bg":"DORMITORY_2","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L10_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"죄, 죄송해요! 시청자 여러분!","JPN":"も、申し訳ありませんでした！　視聴者の皆さん！","ENG":"I-I'm sorry, everyone!","TWN":"非、非常對不起！各位觀眾們！！！"},"stage":{"bg":"DORMITORY_2","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L11_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"다시는! 이런 사고가 없도록! 반성! 또 반성하겠습니다!","JPN":"もう二度と！　こんな事故が起きないように！　反省！　猛反省します！","ENG":"I swear this never happens again! Never! Ever again!","TWN":"以後！絕對不會再出現這種事故！我會反省！再反省！"},"stage":{"bg":"DORMITORY_2","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"DONATION_VOICE_NULL_NULL","text":{"KOREA":"대표님 미야 혼내지 마세요! 제가 대신 맞겠습니다!","JPN":"代表さん、ミヤのこと怒らないであげて！　代わりにこの俺をぶってくださーい！","ENG":"Don't scold Miya, boss lady! I'll take the spanking on her behalf!","TWN":"代表不要再罵米婭了！要罵就讓我代替米婭吧！"},"stage":{"bg":"DORMITORY_2","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L14_1","type":"dialog","speaker":"DONATION_VOICE_NULL_NULL","text":{"KOREA":"아이돌한테 대리사과 시키는 대표는 각성하라!","JPN":"アイドルを盾にして謝罪させる代表こそ猛省すべし！","ENG":"Don't boss her into making an apology!","TWN":"命令偶像道歉的經紀人給我清醒點啊！"},"stage":{"bg":"DORMITORY_2","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L18_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"반성 방송이라니...... 정말 저런 것까지 방송 컨텐츠로 쓸 수 있는 거야?","JPN":"反省配信だなんて……本当にあんなコトまで配信のネタにしていいの？","ENG":"An apology livestream? Does that really make for a good show?","TWN":"竟然是反省直播……連這種東西也能當作直播內容嗎？"},"stage":{"bg":"DORMITORY_2","slots":{"L":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"인터넷방송 무시하지 말라냥. 카메라 앞에서 코만 골아도 사람들이 호응해준다냥.","JPN":"ネット配信の可能性は無限大だにゃ。カメラの前で鼻ちょうちんを作ったって喜んでもらえるにゃ。","ENG":"Don't underestimate the power of online streaming. People go crazy over everything, even if all you do is snore in front of a camera.","TWN":"不要小看網路直播喵。就算是在攝影機前打呼嚕，觀眾們也會做出回應喵。"},"stage":{"bg":"DORMITORY_2","slots":{"L":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"우와...... 싫다.","JPN":"うわぁ……やだぁ……","ENG":"Wow, that's terrible.","TWN":"嗚哇……好討厭。"},"stage":{"bg":"DORMITORY_2","slots":{"L":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"죄송합니...... 앗! 지금 반성 미션이 들어왔어요!","JPN":"ごめんなさ……あっ！　さっそく反省ミッションの要請が入りました！","ENG":"I'm so sorry... Oh! I just received an apology mission!","TWN":"非常對不起……啊！有反省任務來了！"},"stage":{"bg":"DORMITORY_2","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"대표님과 함께 사죄의 물구나무서기 배틀! 패자는 시청자 선별곡 세 개 부르기에요!","JPN":"代表さんも参戦しての逆立ち謝罪バトル！　敗けた人は視聴者のリクエスト曲を3曲歌うんです！","ENG":"As a way to express how sorry we are, we'll see who can stand on our hands longer! The loser will have to sing three selected songs!","TWN":"與經紀人一起道歉的倒立對決！失敗者要唱三首觀眾選擇的歌曲！"},"stage":{"bg":"DORMITORY_2","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"CHOIENA_HB_NULL_NULL","text":{"KOREA":"잠깐! 저는 카운터가 아니기 때문에 이런 공정성에 어긋난 미션은 무효입니다!","JPN":"ちょっと！　私、カウンターでも何でもないのよ。そんなフェアに欠ける勝負には応じられないわ！","ENG":"Hang on! I'm not a Counter. This mission is totally unfair! It doesn't count!","TWN":"等一下！我不是制裁者，這種毫無公平性可言的任務是無效的！"},"stage":{"bg":"DORMITORY_2","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L27_1","type":"dialog","speaker":"CHOIENA_HB_NULL_NULL","text":{"KOREA":"......벽에 한 다리 걸치기까지 허용해준다면 고려해보죠.","JPN":"……壁に脚を片方立てかけていいなら、考えてもいいけれど。","ENG":"Although... I'll consider it if you let me lean one leg on the wall.","TWN":"……但如果能把一條腿靠在牆上，那我就考慮一下。"},"stage":{"bg":"DORMITORY_2","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};